function sliderMain() {
    var swiper = new Swiper('.main .swiper', {
        slidesPerView: '1',
        spaceBetween: 32,
        loop: true,
        speed: 1000,
        autoplay: {
            delay: 3000,
            disableOnInteraction: false
        },
    })
}


$(document).ready(function() {
    sliderMain();

    // Menu
    $('.burger').click(function () {
        $(this).toggleClass('burger--active')
        $('.header__wrap').toggleClass('header__wrap--active')
        $('body').toggleClass('fixed-body')
    })

    // Tabs
    $(".tab").hover(function () {
        let path = $(this).attr("data-tab-path");
        $(this).siblings(".tab").removeClass("tab--active");
        $(this).addClass("tab--active");

        $(this).parents(".tabs").find(".tab__content").removeClass("tab__content--active");
        $(this).parents(".tabs").find(`.tab__content[data-content-path="${path}"]`).addClass("tab__content--active");

        localStorage.setItem("activeTab", path);
    });

    // Accordion
    $(".item-show").click(function () {
        let parent = $(this).parents(".item")
        if($(parent).hasClass("item--active")){
            $(".item").removeClass("item--active")
            $(".item-hidden").slideUp()
        }else{
            $(".item").removeClass("item--active")
            $(parent).addClass("item--active")
            $(".item-hidden").slideUp()
            $(this).siblings(".item-hidden").slideDown()
        }
    })

    // Phone
    $('.input-phone').intlInputPhone({ preferred_country: ['ru'] });
    $('.input-phone input').attr('placeholder', '924 456 65-64');

    // Form
    $('.form-btn').on('click', function() {
        // Получаем родительскую форму
        var form = $(this).closest('.form');
        var isValid = true;

        // Сбрасываем классы ошибок
        form.find('.form-group').removeClass('active active2');

        // Проверка для input type=text
        form.find('input[type="text"]').each(function() {
            if ($(this).val().trim() === '') {
                $(this).closest('.form-group').addClass('active');
                isValid = false;
            } else {
                $(this).closest('.form-group').addClass('active2');
            }
        });

        // Проверка для input type=tel
        form.find('input[type="tel"]').each(function() {
            var phonePattern = /^[0-9\s\-\+\(\)]+$/; // Пример простого паттерна для телефона
            if ($(this).val().trim() === '' || !phonePattern.test($(this).val())) {
                $(this).closest('.form-group').addClass('active');
                isValid = false;
            } else {
                $(this).closest('.form-group').addClass('active2');
            }
        });

        // Проверка для input type=email
        form.find('input[type="email"]').each(function() {
            var emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/; // Простой паттерн для email
            if ($(this).val().trim() !== '' && !emailPattern.test($(this).val())) {
                $(this).closest('.form-group').addClass('active');
                isValid = false;
            } else if ($(this).val().trim() !== '') {
                $(this).closest('.form-group').addClass('active2');
            }
        });

        // Если форма валидна, можно отправить данные или выполнить другие действия
        if (isValid) {
            console.log("Форма валидна!"); // Здесь можно добавить логику отправки формы
        }
    });

    // Modal
    $("[data-modal]").click(function () {
        let modalId = $(this).attr("data-modal")

        openModal(modalId)
    })

    function openModal(modalId){
        $(`#${modalId}`).addClass("modal--active")
        $("body").addClass("fixed-body")
    }

    $(".modal").click(function () {
        closeModal()
    })

    $("._close-modal").click(function () {
        closeModal()
    })

    $(".modal__dialog").click(function (e) {
        e.stopPropagation()
    })


    function closeModal() {
        $('.modal').removeClass("modal--active")
        $("body").removeClass("fixed-body")
    }

})




